def supervisor_node(state: ReviewState):
    analyzer_result = state.get("analyzer_result")
    critic_result   = state.get("critic_result")
    retry_count     = state.get("retry_count", 0)
    max_retries     = state.get("max_retries", 2)

    # analyzer 미실행 → analyzer로
    if analyzer_result is None:
        return {"next_agent": "analyzer"}

    # critic 미실행 또는 재시도 후 pending 상태 → critic으로
    if critic_result is None or critic_result.get("verdict") == "pending":
        return {"next_agent": "critic"}

    verdict     = critic_result.get("verdict", "")
    reason_code = critic_result.get("reason_code", "")

    # 적합 → 종료
    if verdict == "Conformity":
        return {"next_agent": "end"}

    # QUALITY_ERROR 또는 최대 재시도 초과 → 종료
    if reason_code == "QUALITY_ERROR" or retry_count >= max_retries:
        return {"next_agent": "end"}

    # 재시도: repair_directive 보존, critic 결과 pending 처리
    repair_directive = critic_result.get("repair_directive")
    return {
        "next_agent":    "analyzer",
        "retry_count":   retry_count + 1,
        "critic_result": {"verdict": "pending", "repair_directive": repair_directive}
    }

def resolve_calls(g: DependencyGraph) -> None:
    """Second pass: fix cross-file call edges that point to non-existent nodes."""
    node_ids = {n.id for n in g.nodes}
    name_to_ids: dict[str, list[str]] = {}
    for n in g.nodes:
        if n.kind in ("function", "class"):
            name_to_ids.setdefault(n.label, []).append(n.id)

    resolved: list[GraphEdge] = []
    for e in g.edges:
        if e.kind == "calls" and e.target not in node_ids:
            call_name = e.target.split("::")[-1] if "::" in e.target else e.target
            matches = name_to_ids.get(call_name, [])
            for mid in matches:
                if mid != e.source:  # skip self-loop
                    resolved.append(GraphEdge(source=e.source, target=mid, kind="calls"))
        else:
            resolved.append(e)
    g.edges = resolved

def scan(root: Path) -> DependencyGraph:
    g = DependencyGraph()
    for path in sorted(root.rglob("*")):
        if any(part in SKIP_DIRS for part in path.parts):
            continue
        if not path.is_file():
            continue
        for parser in PARSERS:
            if parser.can_parse(path):
                try:
                    sub = parser.parse(path)
                    g.merge(sub)
                except Exception as e:
                    print(f"[warn] {path}: {e}", file=sys.stderr)
                break
    return g

class DependencyGraph:
    nodes: list[GraphNode] = field(default_factory=list)
    edges: list[GraphEdge] = field(default_factory=list)

    def add_node(self, node: GraphNode) -> None:
        if not any(n.id == node.id for n in self.nodes):
            self.nodes.append(node)

    def add_edge(self, edge: GraphEdge) -> None:
        self.edges.append(edge)

    def merge(self, other: "DependencyGraph") -> None:
        for n in other.nodes:
            self.add_node(n)
        self.edges.extend(other.edges)

    def stats(self) -> str:
        kinds = {}
        for n in self.nodes:
            kinds[n.kind] = kinds.get(n.kind, 0) + 1
        edge_kinds = {}
        for e in self.edges:
            edge_kinds[e.kind] = edge_kinds.get(e.kind, 0) + 1
        return (
            f"nodes={len(self.nodes)} {dict(kinds)} | "
            f"edges={len(self.edges)} {dict(edge_kinds)}"
        )

def add_node(self, node: GraphNode) -> None:
        if not any(n.id == node.id for n in self.nodes):
            self.nodes.append(node)

def merge(self, other: "DependencyGraph") -> None:
        for n in other.nodes:
            self.add_node(n)
        self.edges.extend(other.edges)

