class BaseParser(ABC):
    EXTENSIONS: tuple[str, ...]

    def can_parse(self, path: Path) -> bool:
        return path.suffix in self.EXTENSIONS

    @abstractmethod
    def parse(self, path: Path) -> DependencyGraph:
        ...

def _extract_src(src_lines: list[str], start_line: int, max_lines: int = 120) -> str:
    """Extract function/class body by brace counting from start_line (1-indexed)."""
    depth, started = 0, False
    out = []
    for line in src_lines[start_line - 1: start_line - 1 + max_lines]:
        out.append(line)
        for ch in line:
            if ch == '{':
                depth += 1
                started = True
            elif ch == '}':
                depth -= 1
        if started and depth <= 0:
            break
    return "".join(out)

class PythonParser(BaseParser):
    EXTENSIONS = (".py",)

    def parse(self, path: Path) -> DependencyGraph:
        g = DependencyGraph()
        src = path.read_text(encoding="utf-8", errors="replace")
        try:
            tree = ast.parse(src, filename=str(path))
        except SyntaxError:
            return g

        file_id = str(path)
        file_node = GraphNode(id=file_id, label=path.name, kind="file",
                              language="python", file=str(path))
        g.add_node(file_node)

        for node in ast.walk(tree):
            if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
                nid = f"{file_id}::{node.name}"
                func_src = ast.get_source_segment(src, node) or ""
                g.add_node(GraphNode(id=nid, label=node.name, kind="function",
                                     language="python", file=str(path),
                                     line=node.lineno, source_code=func_src))
                g.add_edge(GraphEdge(source=file_id, target=nid, kind="contains"))
                # calls within the function body
                for child in ast.walk(node):
                    if isinstance(child, ast.Call):
                        call_name = self._call_name(child)
                        if call_name:
                            g.add_edge(GraphEdge(source=nid,
                                                 target=f"{file_id}::{call_name}",
                                                 kind="calls"))

            elif isinstance(node, ast.ClassDef):
                cid = f"{file_id}::{node.name}"
                cls_src = ast.get_source_segment(src, node) or ""
                g.add_node(GraphNode(id=cid, label=node.name, kind="class",
                                     language="python", file=str(path),
                                     line=node.lineno, source_code=cls_src))
                g.add_edge(GraphEdge(source=file_id, target=cid, kind="contains"))

            elif isinstance(node, (ast.Import, ast.ImportFrom)):
                for alias in (node.names if hasattr(node, "names") else []):
                    imp_label = alias.name
                    imp_id = f"import::{imp_label}"
                    g.add_node(GraphNode(id=imp_id, label=imp_label,
                                        kind="import", language="python",
                                        file=str(path)))
                    g.add_edge(GraphEdge(source=file_id, target=imp_id,
                                        kind="imports"))

        return g

    @staticmethod
    def _call_name(node: ast.Call) -> str | None:
        if isinstance(node.func, ast.Name):
            return node.func.id
        if isinstance(node.func, ast.Attribute):
            return node.func.attr
        return None

def _call_name(node: ast.Call) -> str | None:
        if isinstance(node.func, ast.Name):
            return node.func.id
        if isinstance(node.func, ast.Attribute):
            return node.func.attr
        return None

def _walk(root: Path):
    for p in root.rglob("*"):
        if any(part in SKIP_DIRS for part in p.parts):
            continue
        if p.is_file():
            yield p

def _parse_requirements(path: Path) -> dict[str, str]:
    """requirements.txt / requirements-dev.txt"""
    out = {}
    for line in path.read_text(errors="replace").splitlines():
        line = line.strip()
        if not line or line.startswith("#") or line.startswith("-"):
            continue
        m = re.match(r"^([\w\-\.]+)\s*([=<>!~^,\s]+[\w\.\*]+)?", line)
        if m:
            pkg = m.group(1).lower().replace("-", "_")
            ver = (m.group(2) or "").strip() or "?"
            out[pkg] = ver
    return out

def _parse_pyproject(path: Path) -> dict[str, str]:
    """pyproject.toml — simple regex, no full TOML parse."""
    out = {}
    content = path.read_text(errors="replace")
    # [tool.poetry.dependencies] or [project] dependencies
    for m in re.finditer(r'"?([\w\-\.]+)"?\s*=\s*["\^~]?([\w\.\*,\s>=<!]+)"?', content):
        pkg = m.group(1).lower().replace("-", "_")
        ver = m.group(2).strip()
        if pkg not in ("python", "name", "version", "description"):
            out.setdefault(pkg, ver)
    return out

def _parse_package_json(path: Path) -> dict[str, str]:
    """package.json — dependencies / devDependencies / peerDependencies"""
    out = {}
    try:
        data = json.loads(path.read_text())
    except Exception:
        return out
    for section in ("dependencies", "devDependencies", "peerDependencies"):
        for pkg, ver in data.get(section, {}).items():
            out.setdefault(pkg, ver)
    return out

def _parse_pom_xml(path: Path) -> dict[str, str]:
    """pom.xml — <artifactId> + <version> pairs."""
    out = {}
    content = path.read_text(errors="replace")
    for m in re.finditer(
        r"<artifactId>([\w\-\.]+)</artifactId>.*?<version>([^<]+)</version>",
        content, re.DOTALL
    ):
        out.setdefault(m.group(1), m.group(2).strip())
    return out

def _parse_gradle(path: Path) -> dict[str, str]:
    """build.gradle — implementation 'group:artifact:version'"""
    out = {}
    for m in re.finditer(
        r"['\"][\w\.\-]+:([\w\.\-]+):([\w\.\-]+)['\"]",
        path.read_text(errors="replace")
    ):
        out.setdefault(m.group(1), m.group(2))
    return out

def resolve_versions(root: Path) -> dict[str, str]:
    """Scan root for manifest files; return {normalized_pkg_name: version_spec}."""
    versions: dict[str, str] = {}

    parsers = {
        "requirements.txt": _parse_requirements,
        "requirements-dev.txt": _parse_requirements,
        "requirements-prod.txt": _parse_requirements,
        "pyproject.toml": _parse_pyproject,
        "package.json": _parse_package_json,
        "pom.xml": _parse_pom_xml,
        "build.gradle": _parse_gradle,
    }

    for path in _walk(root):
        parser = parsers.get(path.name)
        if parser:
            try:
                versions.update(parser(path))
            except Exception:
                pass

    return versions

