def _parse_key_file(path: Path) -> str | None:
    try:
        text = path.read_text(encoding="utf-8")
    except (FileNotFoundError, PermissionError, UnicodeDecodeError):
        return None
    for line in text.splitlines():
        line = line.strip()
        if not line or line.startswith("#"):
            continue
        m = re.match(r"^\s*OPENAI_API_KEY\s*=\s*['\"]?([^'\"]+)['\"]?\s*$", line)
        if m:
            return m.group(1).strip()
        # 단순히 키만 한 줄로 적힌 경우
        if line.startswith("sk-") and "=" not in line:
            return line
    return None

def get_openai_key() -> str | None:
    """우선순위: 환경변수 → ./api_key.txt → ~/api_key.txt"""
    env = os.environ.get("OPENAI_API_KEY")
    if env and env.strip():
        return env.strip()

    cwd_key = Path(os.getcwd()) / "api_key.txt"
    if cwd_key.exists():
        k = _parse_key_file(cwd_key)
        if k:
            return k

    home_key = Path.home() / "api_key.txt"
    if home_key.exists():
        k = _parse_key_file(home_key)
        if k:
            return k

    return None

def _format_categories(categories: list[dict[str, str]]) -> str:
    lines = ["[카테고리]"]
    for c in categories:
        name = c.get("name", "")
        desc = c.get("description", "")
        lines.append(f"- {name}/: {desc}".rstrip())
    return "\n".join(lines)

def _format_confirmed(confirmed_mappings: dict[str, dict[str, Any]]) -> str:
    if not confirmed_mappings:
        return "[이 프로젝트 확정 사례]\n(없음)"
    lines = ["[이 프로젝트 확정 사례]"]
    # 최대 20개만 (토큰 절약)
    for name, info in list(confirmed_mappings.items())[:20]:
        path = info.get("path", "")
        src  = info.get("source", "")
        lines.append(f"{name} → {path} ({src})")
    return "\n".join(lines)

def _format_corrections(corrections: list[dict[str, Any]]) -> str:
    if not corrections:
        return "[수정 이력]\n(없음)"
    lines = ["[수정 이력]"]
    for c in corrections[:10]:
        lines.append(
            f"{c.get('funcName')}: {c.get('fromPath')} → {c.get('toPath')} (사용자 수정)"
        )
    return "\n".join(lines)

def _format_targets(functions: list[dict[str, Any]]) -> str:
    lines = ["[분류 대상]"]
    for f in functions:
        name = f.get("funcName", "")
        src  = (f.get("sourceCode") or "").strip()
        # 너무 긴 함수는 자르기 (토큰 절약)
        if len(src) > 1200:
            src = src[:1200] + "\n# ... (truncated)"
        lines.append(f"\n함수명: {name}\n코드:\n{src}")
    return "\n".join(lines)

def _extract_json(text: str) -> dict[str, Any]:
    if not text:
        return {}
    # ```json ... ``` 펜스 제거
    fence = re.search(r"```(?:json)?\s*(\{.*\})\s*```", text, re.DOTALL)
    if fence:
        text = fence.group(1)
    # 가장 바깥 중괄호 블록만 추출
    start = text.find("{")
    end   = text.rfind("}")
    if start == -1 or end == -1 or end <= start:
        return {}
    snippet = text[start : end + 1]
    try:
        obj = json.loads(snippet)
        return obj if isinstance(obj, dict) else {}
    except json.JSONDecodeError:
        return {}

def classify_functions(
    functions: list[dict[str, Any]],
    categories: list[dict[str, str]],
    confirmed_mappings: dict[str, dict[str, Any]],
    corrections: list[dict[str, Any]],
) -> dict[str, dict[str, Any]]:
    """
    OpenAI LLM으로 함수를 분류.
    실패 시 빈 dict 반환 (caller가 fallback 처리).

    반환 형식:
      { funcName: {"path": str, "confidence": float, "reason": str} }
    """
    if not functions:
        return {}

    api_key = get_openai_key()
    if not api_key:
        return {}

    try:
        from openai import OpenAI  # type: ignore
    except ImportError:
        return {}

    user_prompt = _build_user_prompt(
        functions, categories, confirmed_mappings, corrections
    )

    try:
        client = OpenAI(api_key=api_key)
        resp = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=[
                {"role": "system", "content": _SYSTEM_PROMPT},
                {"role": "user",   "content": user_prompt},
            ],
            temperature=0.0,
            max_tokens=1500,
            response_format={"type": "json_object"},
            timeout=30,
        )
        content = resp.choices[0].message.content or ""
    except Exception:
        return {}

    raw = _extract_json(content)
    if not raw:
        return {}

    # 정규화: path/confidence/reason 키만 통과
    result: dict[str, dict[str, Any]] = {}
    for name, info in raw.items():
        if not isinstance(info, dict):
            continue
        path = info.get("path") or info.get("file_path")
        if not isinstance(path, str) or not path.strip():
            continue
        try:
            conf = float(info.get("confidence", 0.7))
        except (TypeError, ValueError):
            conf = 0.7
        conf = max(0.0, min(1.0, conf))
        reason = info.get("reason", "") if isinstance(info.get("reason", ""), str) else ""
        result[name] = {
            "path":       path.strip(),
            "confidence": conf,
            "reason":     reason,
        }
    return result

class StateDB:
    """SQLite 기반 NoteBook_MOD State 저장소."""

    def __init__(self, db_path: str):
        self.db_path = db_path
        parent = os.path.dirname(db_path)
        if parent and not os.path.isdir(parent):
            os.makedirs(parent, exist_ok=True)
        self._ensure_schema()
        self._seed_categories()

    # ── 내부 헬퍼 ────────────────────────────────────────
    def _connect(self) -> sqlite3.Connection:
        conn = sqlite3.connect(self.db_path)
        conn.row_factory = sqlite3.Row
        return conn

    def _ensure_schema(self) -> None:
        with self._connect() as conn:
            conn.executescript(
                """
                CREATE TABLE IF NOT EXISTS confirmed_mappings (
                  func_name    TEXT PRIMARY KEY,
                  file_path    TEXT NOT NULL,
                  source       TEXT NOT NULL,
                  confidence   REAL DEFAULT 1.0,
                  confirmed_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
                );
                CREATE TABLE IF NOT EXISTS corrections (
                  id           INTEGER PRIMARY KEY AUTOINCREMENT,
                  func_name    TEXT NOT NULL,
                  from_path    TEXT NOT NULL,
                  to_path      TEXT NOT NULL,
                  corrected_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
                );
                CREATE TABLE IF NOT EXISTS categories (
                  name        TEXT PRIMARY KEY,
                  description TEXT DEFAULT ''
                );
                """
            )

    def _seed_categories(self) -> None:
        """카테고리 테이블이 비어 있으면 기본값 삽입."""
        with self._connect() as conn:
            cur = conn.execute("SELECT COUNT(*) AS n FROM categories;")
            n = cur.fetchone()["n"]
            if n == 0:
                conn.executemany(
                    "INSERT INTO categories(name, description) VALUES (?, ?);",
                    _DEFAULT_CATEGORIES,
                )

    # ── confirmed_mappings ──────────────────────────────
    def get_mapping(self, func_name: str) -> str | None:
        with self._connect() as conn:
            row = conn.execute(
                "SELECT file_path FROM confirmed_mappings WHERE func_name = ?;",
                (func_name,),
            ).fetchone()
            return row["file_path"] if row else None

    def set_mapping(
        self,
        func_name: str,
        file_path: str,
        source: str,
        confidence: float = 1.0,
    ) -> None:
        with self._connect() as conn:
            conn.execute(
                """
                INSERT INTO confirmed_mappings(func_name, file_path, source, confidence)
                VALUES (?, ?, ?, ?)
                ON CONFLICT(func_name) DO UPDATE SET
                    file_path    = excluded.file_path,
                    source       = excluded.source,
                    confidence   = excluded.confidence,
                    confirmed_at = CURRENT_TIMESTAMP;
                """,
                (func_name, file_path, source, float(confidence)),
            )

    def get_all_mappings(self) -> dict[str, dict[str, Any]]:
        with self._connect() as conn:
            rows = conn.execute(
                "SELECT func_name, file_path, source, confidence FROM confirmed_mappings;"
            ).fetchall()
            return {
                r["func_name"]: {
                    "path":       r["file_path"],
                    "source":     r["source"],
                    "confidence": r["confidence"],
                }
                for r in rows
            }

    # ── corrections ─────────────────────────────────────
    def add_correction(self, func_name: str, from_path: str, to_path: str) -> None:
        with self._connect() as conn:
            conn.execute(
                """
                INSERT INTO corrections(func_name, from_path, to_path)
                VALUES (?, ?, ?);
                """,
                (func_name, from_path, to_path),
            )

    def get_corrections(self) -> list[dict[str, Any]]:
        with self._connect() as conn:
            rows = conn.execute(
                """
                SELECT func_name, from_path, to_path, corrected_at
                FROM corrections
                ORDER BY corrected_at DESC
                LIMIT 50;
                """
            ).fetchall()
            return [
                {
                    "funcName":    r["func_name"],
                    "fromPath":    r["from_path"],
                    "toPath":      r["to_path"],
                    "correctedAt": r["corrected_at"],
                }
                for r in rows
            ]

    # ── categories ──────────────────────────────────────
    def get_categories(self) -> list[dict[str, str]]:
        with self._connect() as conn:
            rows = conn.execute(
                "SELECT name, description FROM categories ORDER BY name;"
            ).fetchall()
            return [
                {"name": r["name"], "description": r["description"] or ""}
                for r in rows
            ]

    def set_category(self, name: str, description: str = "") -> None:
        with self._connect() as conn:
            conn.execute(
                """
                INSERT INTO categories(name, description)
                VALUES (?, ?)
                ON CONFLICT(name) DO UPDATE SET description = excluded.description;
                """,
                (name, description or ""),
            )

    def delete_category(self, name: str) -> None:
        with self._connect() as conn:
            conn.execute("DELETE FROM categories WHERE name = ?;", (name,))

