export function inferFilePath(funcName: string, isClass: boolean): string {
  // 파일명용: 선행 _ 제거 (private helper는 모듈명에 _ 불필요)
  const fileName = funcName.replace(/^_+/, '');
  const lower    = funcName.toLowerCase();

  if (isClass) {
    if (/state$/i.test(funcName))   return 'state.py';
    if (/config$/i.test(funcName))  return 'config.py';
    if (/schema$/i.test(funcName))  return 'schema.py';
    return `models/${fileName}.py`;
  }

  // 에이전트 노드
  if (/_node$/.test(lower))  return `agents/${fileName}.py`;
  if (/_agent$/.test(lower)) return `agents/${fileName}.py`;

  // 그래프 / 라우팅
  if (/^_?build_/.test(lower))      return `graph/${fileName}.py`;
  if (/^_?route_/.test(lower))      return `graph/${fileName}.py`;
  if (/^_?compile_/.test(lower))    return `graph/${fileName}.py`;
  if (/^_?create_graph/.test(lower)) return `graph/${fileName}.py`;

  // 데이터베이스
  if (/^_?init_db/.test(lower))             return `db/${fileName}.py`;
  if (/^_?save_/.test(lower))               return `db/${fileName}.py`;
  if (/^_?(get|fetch)_.*db/.test(lower))    return `db/${fileName}.py`;

  // 유틸리티 / 로더
  if (/^_?(load|get|read|fetch)_/.test(lower)) return `utils/${fileName}.py`;
  if (/^_?(setup|configure)_/.test(lower))     return `utils/${fileName}.py`;

  return `${fileName}.py`;
}

export function analyzeCell(source: string): InferredModule[] {
  const lines = source.split('\n');
  const modules: InferredModule[] = [];

  const writefileMatch = WRITEFILE_PATTERN.exec(lines[0] ?? '');
  // %%writefile 셀이라도 함수별 경로는 이름 규칙으로 독립 추론

  for (const line of lines) {
    const m = FUNC_PATTERN.exec(line);
    if (!m) continue;
    const isClass = m[2] === 'class';
    const funcName = m[3];
    if (funcName === '_') continue;          // 익명 패턴 스킵
    if (funcName.startsWith('__')) continue; // dunder 스킵

    const filePath = inferFilePath(funcName, isClass);
    modules.push({ funcName, filePath, isClass });
  }

  return modules;
}

export class ModuleBadgeWidget extends WidgetType {
  constructor(
    private readonly funcName: string,
    private readonly filePath: string,
    private readonly sourceCode: string,
    private readonly onOpen: (path: string) => void,
    private readonly onExpand: (view: EditorView) => void
  ) {
    super();
  }

  toDOM(view: EditorView): HTMLElement {
    const wrap = document.createElement('span');
    wrap.className = 'nbmod-badge';
    wrap.setAttribute('data-func', this.funcName);

    const icon = document.createElement('span');
    icon.textContent = '📄';
    icon.style.marginRight = '3px';

    const label = document.createElement('span');
    label.className = 'nbmod-badge__label';
    label.textContent = this.funcName;

    const hint = document.createElement('span');
    hint.className = 'nbmod-badge__hint';
    hint.textContent = ` · ${this.filePath}`;

    wrap.appendChild(icon);
    wrap.appendChild(label);
    wrap.appendChild(hint);

    wrap.addEventListener('mouseenter', () => this._showTooltip(wrap));
    wrap.addEventListener('mouseleave', () => {
      setTimeout(() => { if (!activeTooltip?.matches(':hover')) removeTooltip(); }, 120);
    });
    wrap.addEventListener('click', (e) => {
      e.stopPropagation();
      removeTooltip();
      this.onOpen(this.filePath);
    });
    wrap.addEventListener('dblclick', (e) => {
      e.stopPropagation();
      removeTooltip();
      this.onExpand(view);
    });

    return wrap;
  }

  private _showTooltip(anchor: HTMLElement): void {
    removeTooltip();
    const t = document.createElement('div');
    t.className = 'nbmod-tooltip';

    const header = document.createElement('div');
    header.className = 'nbmod-tooltip__header';
    header.innerHTML = `<span>📄</span> <span class="nbmod-tooltip__path">${this.filePath}</span>`;

    const pre = document.createElement('pre');
    pre.className = 'nbmod-tooltip__code';
    pre.textContent = this.sourceCode;

    const footer = document.createElement('div');
    footer.className = 'nbmod-tooltip__footer';
    footer.textContent = 'click: 파일 열기  •  dblclick: 인라인 전개';

    t.appendChild(header);
    t.appendChild(pre);
    t.appendChild(footer);

    const rect = anchor.getBoundingClientRect();
    t.style.position = 'fixed';
    t.style.top  = `${rect.bottom + 6}px`;
    t.style.left = `${rect.left}px`;
    t.style.zIndex = '9999';

    document.body.appendChild(t);
    activeTooltip = t;
    t.addEventListener('mouseleave', removeTooltip);
  }

  eq(other: ModuleBadgeWidget): boolean {
    return this.funcName === other.funcName && this.filePath === other.filePath;
  }

  ignoreEvent(): boolean { return false; }
}

function removeTooltip() {
  activeTooltip?.remove();
  activeTooltip = null;
}

export class CorrectionDropdown {
